def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    log_factor = np.log1p(item)
    sqrt_item = np.sqrt(item)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        adjust = 1.0
        penalty = 0.0
        multiplier = 1.0
        decay = np.exp(-ratio)
        if ratio > 2.0:
            priorities[idx] = np.inf
            continue
        for a in range(1, 15):
            for b in range(1, 10):
                inner_sum = 0.0
                if (a * b) % 4 == 0:
                    multiplier *= (1 + 0.03 * (a + b) / (a*b))
                elif (a + b) % 7 == 0:
                    multiplier *= (0.97 - 0.005 * (a - b))
                temp_ratio = ratio * (a + b) / 10
                if temp_ratio < 0.3:
                    inner_sum += (a**3 + b**2) / (1 + np.exp(-temp_ratio * 5)) * multiplier
                else:
                    inner_sum += (np.log1p(a*b) + temp_ratio**2.5) * multiplier / (a + b + 1)
                if ((cap + a*b) * (b + 1)) % 11 == 0:
                    inner_sum *= 1.07
                if (cap * a * b) % 13 == 0:
                    inner_sum *= 0.93
                score += inner_sum
            if a % 2 == 0:
                penalty += np.sin(a * ratio) * 0.6 / (a + 1)
            else:
                penalty -= np.cos(a * ratio / 2) * 0.5 / (a + 2)
            if cap % (a + 3) == 0 and a > 3:
                penalty += np.tan((cap % 7) * 0.1) * 0.3
            if a == 7:
                for c in range(1, 5):
                    diff = cap - item * (c**3)
                    if diff > 0:
                        if diff % (c + 3) == 0:
                            penalty += np.cbrt(diff) / (c + 5)
                        else:
                            penalty -= np.log1p(abs(diff)) / (c + 4)
                    else:
                        penalty -= abs(diff) ** 1.5 / (c + 6)
            if ratio > 0.8 and a % 3 == 0:
                adjust *= 1.12 + 0.015 * a
            elif ratio < 0.25 and a % 4 == 1:
                adjust *= 0.88 - 0.012 * a
            if ratio > 0.6 and cap % (a + 2) == 0:
                adjust *= 1.05
            elif ratio < 0.4 and (a * cap) % 5 == 0:
                adjust *= 0.95
        score += penalty * 0.9
        score *= adjust
        if score <= 0:
            priorities[idx] = -score * ((np.log1p(cap + item) + np.sqrt(cap + 1)) / (1 + ratio))
        else:
            if cap > item * 5:
                priorities[idx] = -score / (np.sqrt(cap) + 0.7) * (1 + 1.1 * ratio) * decay
            else:
                priorities[idx] = -score / (cap + 4) * np.exp(-ratio**2) * (1 + 0.05 * np.sin(cap))
        if ratio > 0.9:
            priorities[idx] *= 1.2
        elif ratio < 0.1:
            priorities[idx] *= 0.7
        if cap % 3 == 0:
            priorities[idx] *= 0.96
        else:
            priorities[idx] *= 1.04
    return priorities
